# ==============================================================================
# ENUMS & CONSTANTS
# ==============================================================================

class QuestStatus(Enum):
    DRAFT = "draft"
    ACTIVE = "active"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"
    FAILED = "failed"
    ABANDONED = "abandoned"


class QuestDifficulty(Enum):
    TRIVIAL = "trivial"
    EASY = "easy"
    MEDIUM = "medium"
    HARD = "hard"
    LEGENDARY = "legendary"


class SkillCategory(Enum):
    COMBAT = "combat"
    MAGIC = "magic"
    STEALTH = "stealth"
    CRAFTING = "crafting"
    SOCIAL = "social"
    EXPLORATION = "exploration"
    SURVIVAL = "survival"


class CollaborationRole(Enum):
    OWNER = "owner"
    EDITOR = "editor"
    VIEWER = "viewer"


class EventType(Enum):
    QUEST_CREATED = "quest_created"
    QUEST_UPDATED = "quest_updated"
    QUEST_COMPLETED = "quest_completed"
    QUEST_DELETED = "quest_deleted"
    SKILL_ADDED = "skill_added"
    SKILL_UPDATED = "skill_updated"
    SKILL_REMOVED = "skill_removed"
    COLLABORATOR_JOINED = "collaborator_joined"
    COLLABORATOR_LEFT = "collaborator_left"
    MESSAGE_SENT = "message_sent"
    PLAN_UPDATED = "plan_updated"


# ==============================================================================
# EXCEPTIONS
# ==============================================================================

class QuestHubError(Exception):
    """Base exception for QuestHub."""
    pass


class AuthenticationError(QuestHubError):
    """Raised when authentication fails."""
    pass


class AuthorizationError(QuestHubError):
    """Raised when user lacks permission."""
    pass


class NotFoundError(QuestHubError):
    """Raised when a resource is not found."""
    pass


class ValidationError(QuestHubError):
    """Raised when input validation fails."""
    pass


class ConflictError(QuestHubError):
    """Raised when a resource conflict occurs."""
    pass


