# ==============================================================================
# DATABASE LAYER
# ==============================================================================

class Database:
    """Thread-safe in-memory database with indexing and querying support."""

    def __init__(self):
        self._lock = threading.RLock()
        self._users: dict[str, User] = {}
        self._quests: dict[str, Quest] = {}
        self._skill_plans: dict[str, SkillPlan] = {}
        self._collaboration_sessions: dict[str, CollaborationSession] = {}
        self._sessions: dict[str, Session] = {}
        self._messages: dict[str, Message] = {}

        # Indexes
        self._username_index: dict[str, str] = {}  # username_lower -> user_id
        self._email_index: dict[str, str] = {}  # email_lower -> user_id
        self._user_quests_index: dict[str, set] = {}  # user_id -> set of quest_ids
        self._user_plans_index: dict[str, set] = {}  # user_id -> set of plan_ids
        self._tag_index: dict[str, set] = {}  # tag -> set of quest_ids
        self._session_messages_index: dict[str, list] = {}  # session_id -> [msg_ids]

    @property
    def lock(self):
        return self._lock

    # --- User operations ---

    def create_user(self, user: User) -> User:
        with self._lock:
            if user.username.lower() in self._username_index:
                raise ConflictError(f"Username '{user.username}' already exists")
            if user.email.lower() in self._email_index:
                raise ConflictError(f"Email '{user.email}' already registered")
            self._users[user.id] = user
            self._username_index[user.username.lower()] = user.id
            self._email_index[user.email.lower()] = user.id
            self._user_quests_index[user.id] = set()
            self._user_plans_index[user.id] = set()
            return copy.deepcopy(user)

    def get_user(self, user_id: str) -> User:
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError(f"User '{user_id}' not found")
            return copy.deepcopy(self._users[user_id])

    def get_user_by_username(self, username: str) -> User:
        with self._lock:
            uid = self._username_index.get(username.lower())
            if uid is None:
                raise NotFoundError(f"User '{username}' not found")
            return copy.deepcopy(self._users[uid])

    def get_user_by_email(self, email: str) -> User:
        with self._lock:
            uid = self._email_index.get(email.lower())
            if uid is None:
                raise NotFoundError(f"User with email '{email}' not found")
            return copy.deepcopy(self._users[uid])

    def update_user(self, user: User) -> User:
        with self._lock:
            if user.id not in self._users:
                raise NotFoundError(f"User '{user.id}' not found")
            old_user = self._users[user.id]
            if old_user.username.lower() != user.username.lower():
                if user.username.lower() in self._username_index:
                    raise ConflictError(f"Username '{user.username}' already exists")
                del self._username_index[old_user.username.lower()]
                self._username_index[user.username.lower()] = user.id
            if old_user.email.lower() != user.email.lower():
                if user.email.lower() in self._email_index:
                    raise ConflictError(f"Email '{user.email}' already registered")
                del self._email_index[old_user.email.lower()]
                self._email_index[user.email.lower()] = user.id
            self._users[user.id] = user
            return copy.deepcopy(user)

    def delete_user(self, user_id: str) -> None:
        with self._lock:
            if user_id not in self._users:
                raise NotFoundError(f"User '{user_id}' not found")
            user = self._users[user_id]
            del self._username_index[user.username.lower()]
            del self._email_index[user.email.lower()]
            del self._users[user_id]
            if user_id in self._user_quests_index:
                del self._user_quests_index[user_id]
            if user_id in self._user_plans_index:
                del self._user_plans_index[user_id]

    def list_users(self, offset: int = 0, limit: int = 50) -> list[User]:
        with self._lock:
            users = list(self._users.values())
            return [copy.deepcopy(u) for u in users[offset:offset + limit]]

    # --- Quest operations ---

    def create_quest(self, quest: Quest) -> Quest:
        with self._lock:
            self._quests[quest.id] = quest
            if quest.owner_id in self._user_quests_index:
                self._user_quests_index[quest.owner_id].add(quest.id)
            for tag in quest.tags:
                if tag not in self._tag_index:
                    self._tag_index[tag] = set()
                self._tag_index[tag].add(quest.id)
            return copy.deepcopy(quest)

    def get_quest(self, quest_id: str) -> Quest:
        with self._lock:
            if quest_id not in self._quests:
                raise NotFoundError(f"Quest '{quest_id}' not found")
            return copy.deepcopy(self._quests[quest_id])

    def update_quest(self, quest: Quest) -> Quest:
        with self._lock:
            if quest.id not in self._quests:
                raise NotFoundError(f"Quest '{quest.id}' not found")
            old_quest = self._quests[quest.id]
            for tag in old_quest.tags:
                if tag in self._tag_index:
                    self._tag_index[tag].discard(quest.id)
            for tag in quest.tags:
                if tag not in self._tag_index:
                    self._tag_index[tag] = set()
                self._tag_index[tag].add(quest.id)
            self._quests[quest.id] = quest
            return copy.deepcopy(quest)

    def delete_quest(self, quest_id: str) -> None:
        with self._lock:
            if quest_id not in self._quests:
                raise NotFoundError(f"Quest '{quest_id}' not found")
            quest = self._quests[quest_id]
            for tag in quest.tags:
                if tag in self._tag_index:
                    self._tag_index[tag].discard(quest_id)
            if quest.owner_id in self._user_quests_index:
                self._user_quests_index[quest.owner_id].discard(quest_id)
            del self._quests[quest_id]

    def list_quests(self, owner_id: Optional[str] = None, status: Optional[str] = None,
                    tag: Optional[str] = None, offset: int = 0, limit: int = 50) -> list[Quest]:
        with self._lock:
            if owner_id:
                quest_ids = self._user_quests_index.get(owner_id, set())
                quests = [self._quests[qid] for qid in quest_ids if qid in self._quests]
            elif tag:
                quest_ids = self._tag_index.get(tag, set())
                quests = [self._quests[qid] for qid in quest_ids if qid in self._quests]
            else:
                quests = list(self._quests.values())
            if status:
                quests = [q for q in quests if q.status == status]
            quests.sort(key=lambda q: q.created_at, reverse=True)
            return [copy.deepcopy(q) for q in quests[offset:offset + limit]]

    def search_quests(self, query: str, offset: int = 0, limit: int = 50) -> list[Quest]:
        with self._lock:
            query_lower = query.lower()
            results = []
            for quest in self._quests.values():
                if (query_lower in quest.title.lower() or
                        query_lower in quest.description.lower() or
                        any(query_lower in tag.lower() for tag in quest.tags)):
                    results.append(quest)
            results.sort(key=lambda q: q.created_at, reverse=True)
            return [copy.deepcopy(q) for q in results[offset:offset + limit]]

    # --- Skill Plan operations ---

    def create_skill_plan(self, plan: SkillPlan) -> SkillPlan:
        with self._lock:
            self._skill_plans[plan.id] = plan
            if plan.owner_id in self._user_plans_index:
                self._user_plans_index[plan.owner_id].add(plan.id)
            return copy.deepcopy(plan)

    def get_skill_plan(self, plan_id: str) -> SkillPlan:
        with self._lock:
            if plan_id not in self._skill_plans:
                raise NotFoundError(f"Skill plan '{plan_id}' not found")
            return copy.deepcopy(self._skill_plans[plan_id])

    def update_skill_plan(self, plan: SkillPlan) -> SkillPlan:
        with self._lock:
            if plan.id not in self._skill_plans:
                raise NotFoundError(f"Skill plan '{plan.id}' not found")
            self._skill_plans[plan.id] = plan
            return copy.deepcopy(plan)

    def delete_skill_plan(self, plan_id: str) -> None:
        with self._lock:
            if plan_id not in self._skill_plans:
                raise NotFoundError(f"Skill plan '{plan_id}' not found")
            plan = self._skill_plans[plan_id]
            if plan.owner_id in self._user_plans_index:
                self._user_plans_index[plan.owner_id].discard(plan_id)
            del self._skill_plans[plan_id]

    def list_skill_plans(self, owner_id: Optional[str] = None,
                         offset: int = 0, limit: int = 50) -> list[SkillPlan]:
        with self._lock:
            if owner_id:
                plan_ids = self._user_plans_index.get(owner_id, set())
                plans = [self._skill_plans[pid] for pid in plan_ids if pid in self._skill_plans]
            else:
                plans = [p for p in self._skill_plans.values() if p.is_public]
            plans.sort(key=lambda p: p.created_at, reverse=True)
            return [copy.deepcopy(p) for p in plans[offset:offset + limit]]

    # --- Collaboration Session operations ---

    def create_collaboration_session(self, session: CollaborationSession) -> CollaborationSession:
        with self._lock:
            self._collaboration_sessions[session.id] = session
            self._session_messages_index[session.id] = []
            return copy.deepcopy(session)

    def get_collaboration_session(self, session_id: str) -> CollaborationSession:
        with self._lock:
            if session_id not in self._collaboration_sessions:
                raise NotFoundError(f"Collaboration session '{session_id}' not found")
            return copy.deepcopy(self._collaboration_sessions[session_id])

    def update_collaboration_session(self, session: CollaborationSession) -> CollaborationSession:
        with self._lock:
            if session.id not in self._collaboration_sessions:
                raise NotFoundError(f"Collaboration session '{session.id}' not found")
            self._collaboration_sessions[session.id] = session
            return copy.deepcopy(session)

    def find_collaboration_session(self, resource_type: str, resource_id: str) -> Optional[CollaborationSession]:
        with self._lock:
            for session in self._collaboration_sessions.values():
                if session.resource_type == resource_type and session.resource_id == resource_id and session.is_active:
                    return copy.deepcopy(session)
            return None

    # --- Message operations ---

    def add_message(self, message: Message) -> Message:
        with self._lock:
            self._messages[message.id] = message
            if message.session_id in self._session_messages_index:
                self._session_messages_index[message.session_id].append(message.id)
            return copy.deepcopy(message)

    def get_messages(self, session_id: str, offset: int = 0, limit: int = 100) -> list[Message]:
        with self._lock:
            msg_ids = self._session_messages_index.get(session_id, [])
            messages = [self._messages[mid] for mid in msg_ids if mid in self._messages]
            return [copy.deepcopy(m) for m in messages[offset:offset + limit]]

    # --- Auth Session operations ---

    def create_session(self, session: Session) -> Session:
        with self._lock:
            self._sessions[session.token] = session
            return copy.deepcopy(session)

    def get_session(self, token: str) -> Optional[Session]:
        with self._lock:
            session = self._sessions.get(token)
            if session and session.is_valid:
                return copy.deepcopy(session)
            return None

    def invalidate_session(self, token: str) -> None:
        with self._lock:
            if token in self._sessions:
                self._sessions[token].is_valid = False

    # --- Stats ---

    def get_stats(self) -> dict:
        with self._lock:
            return {
                "users": len(self._users),
                "quests": len(self._quests),
                "skill_plans": len(self._skill_plans),
                "collaboration_sessions": len(self._collaboration_sessions),
                "messages": len(self._messages),
            }


# ==============================================================================
# EVENT SYSTEM (Real-time pub/sub)
# ==============================================================================

class EventBus:
    """Thread-safe publish/subscribe event bus for real-time updates."""

    def __init__(self):
        self._lock = threading.RLock()
        self._subscribers: dict[str, list[Callable]] = {}  # channel -> [callbacks]
        self._event_log: list[dict] = []
        self._max_log_size = 10000

    def subscribe(self, channel: str, callback: Callable) -> str:
        """Subscribe to a channel. Returns subscription id."""
        sub_id = str(uuid.uuid4())
        with self._lock:
            if channel not in self._subscribers:
                self._subscribers[channel] = []
            self._subscribers[channel].append((sub_id, callback))
        return sub_id

    def unsubscribe(self, channel: str, sub_id: str) -> None:
        """Remove a subscription."""
        with self._lock:
            if channel in self._subscribers:
                self._subscribers[channel] = [
                    (sid, cb) for sid, cb in self._subscribers[channel] if sid != sub_id
                ]

    def publish(self, channel: str, event_type: str, data: dict, sender_id: str = "") -> None:
        """Publish an event to a channel."""
        event = {
            "id": str(uuid.uuid4()),
            "channel": channel,
            "type": event_type,
            "data": data,
            "sender_id": sender_id,
            "timestamp": _now_iso(),
        }
        with self._lock:
            self._event_log.append(event)
            if len(self._event_log) > self._max_log_size:
                self._event_log = self._event_log[-self._max_log_size // 2:]
            subscribers = list(self._subscribers.get(channel, []))

        for sub_id, callback in subscribers:
            try:
                callback(event)
            except Exception:
                pass

    def get_recent_events(self, channel: str, limit: int = 50) -> list[dict]:
        """Get recent events from a channel."""
        with self._lock:
            events = [e for e in self._event_log if e["channel"] == channel]
            return events[-limit:]


