# SERVICE LAYER
# ==============================================================================

def _now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def _hash_password(password: str) -> str:
    salt = secrets.token_hex(16)
    h = hashlib.pbkdf2_hmac("sha256", password.encode(), salt.encode(), 100000)
    return f"{salt}:{h.hex()}"


def _verify_password(password: str, password_hash: str) -> bool:
    try:
        salt, h = password_hash.split(":")
        computed = hashlib.pbkdf2_hmac("sha256", password.encode(), salt.encode(), 100000)
        return computed.hex() == h
    except (ValueError, AttributeError):
        return False


class AuthService:
    """Handles user authentication and session management."""

    def __init__(self, db: Database):
        self._db = db
        self._lock = db.lock
        self._session_duration = 86400  # 24 hours

    def register(self, username: str, email: str, password: str,
                 display_name: str = "") -> User:
        if not username or len(username) < 3:
            raise ValidationError("Username must be at least 3 characters")
        if not re.match(r'^[a-zA-Z0-9_]+$', username):
            raise ValidationError("Username can only contain letters, numbers, and underscores")
        if not email or not re.match(r'^[^@]+@[^@]+\.[^@]+$', email):
            raise ValidationError("Invalid email address")
        if not password or len(password) < 6:
            raise ValidationError("Password must be at least 6 characters")

        now = _now_iso()
        user = User(
            id=str(uuid.uuid4()),
            username=username,
            email=email,
            password_hash=_hash_password(password),
            display_name=display_name or username,
            created_at=now,
            updated_at=now,
        )
        return self._db.create_user(user)

    def login(self, username_or_email: str, password: str) -> tuple[User, str]:
        try:
            if "@" in username_or_email:
                user = self._db.get_user_by_email(username_or_email)
            else:
                user = self._db.get_user_by_username(username_or_email)
        except NotFoundError:
            raise AuthenticationError("Invalid credentials")

        if not user.is_active:
            raise AuthenticationError("Account is deactivated")
        if not _verify_password(password, user.password_hash):
            raise AuthenticationError("Invalid credentials")

        now = datetime.now(timezone.utc)
        session = Session(
            token=secrets.token_urlsafe(32),
            user_id=user.id,
            created_at=now.isoformat(),
            expires_at=(datetime.fromtimestamp(
                now.timestamp() + self._session_duration, tz=timezone.utc
            )).isoformat(),
        )
        self._db.create_session(session)
        return user, session.token

    def authenticate(self, token: str) -> User:
        if not token:
            raise AuthenticationError("No authentication token provided")
        session = self._db.get_session(token)
        if session is None:
            raise AuthenticationError("Invalid or expired session")
        now = datetime.now(timezone.utc).isoformat()
        if now > session.expires_at:
            self._db.invalidate_session(token)
            raise AuthenticationError("Session expired")
        return self._db.get_user(session.user_id)

    def logout(self, token: str) -> None:
        self._db.invalidate_session(token)

    def change_password(self, user_id: str, old_password: str, new_password: str) -> None:
        user = self._db.get_user(user_id)
        if not _verify_password(old_password, user.password_hash):
            raise AuthenticationError("Current password is incorrect")
        if len(new_password) < 6:
            raise ValidationError("New password must be at least 6 characters")
        user.password_hash = _hash_password(new_password)
        user.updated_at = _now_iso()
        self._db.update_user(user)


class QuestService:
    """Manages quest CRUD and lifecycle."""

    def __init__(self, db: Database, event_bus: EventBus):
        self._db = db
        self._lock = db.lock
        self._event_bus = event_bus

    def create_quest(self, owner_id: str, title: str, description: str,
                     difficulty: str = QuestDifficulty.MEDIUM.value,
                     objectives: Optional[list] = None,
                     rewards: Optional[dict] = None,
                     tags: Optional[list] = None,
                     deadline: Optional[str] = None,
                     parent_quest_id: Optional[str] = None) -> Quest:
        self._db.get_user(owner_id)  # Validates user exists

        if not title or len(title.strip()) == 0:
            raise ValidationError("Quest title is required")
        if len(title) > 200:
            raise ValidationError("Quest title must be 200 characters or less")

        if difficulty not in [d.value for d in QuestDifficulty]:
            raise ValidationError(f"Invalid difficulty: {difficulty}")

        now = _now_iso()
        quest_objectives = []
        if objectives:
            for i, obj in enumerate(objectives):
                quest_objectives.append({
                    "id": str(uuid.uuid4()),
                    "description": obj if isinstance(obj, str) else obj.get("description", ""),
                    "is_completed": False,
                    "completed_at": None,
                    "order": i,
                })

        quest = Quest(
            id=str(uuid.uuid4()),
            title=title.strip(),
            description=description.strip() if description else "",
            owner_id=owner_id,
            difficulty=difficulty,
            objectives=quest_objectives,
            rewards=rewards or {},
            tags=tags or [],
            deadline=deadline,
            parent_quest_id=parent_quest_id,
            created_at=now,
            updated_at=now,
        )

        if parent_quest_id:
            parent = self._db.get_quest(parent_quest_id)
            parent.sub_quest_ids.append(quest.id)
            self._db.update_quest(parent)

        result = self._db.create_quest(quest)
        self._event_bus.publish(
            f"user:{owner_id}", EventType.QUEST_CREATED.value,
            {"quest_id": result.id, "title": result.title}, owner_id
        )
        return result

    def get_quest(self, quest_id: str, user_id: Optional[str] = None) -> Quest:
        quest = self._db.get_quest(quest_id)
        return quest

    def update_quest(self, quest_id: str, user_id: str, **kwargs) -> Quest:
        quest = self._db.get_quest(quest_id)
        if quest.owner_id != user_id and user_id not in quest.collaborator_ids:
            raise AuthorizationError("You don't have permission to update this quest")

        if "title" in kwargs:
            title = kwargs["title"]
            if not title or len(title.strip()) == 0:
                raise ValidationError("Quest title is required")
            quest.title = title.strip()
        if "description" in kwargs:
            quest.description = kwargs["description"]
        if "difficulty" in kwargs:
            if kwargs["difficulty"] not in [d.value for d in QuestDifficulty]:
                raise ValidationError(f"Invalid difficulty: {kwargs['difficulty']}")
            quest.difficulty = kwargs["difficulty"]
        if "tags" in kwargs:
            quest.tags = kwargs["tags"]
        if "deadline" in kwargs:
            quest.deadline = kwargs["deadline"]
        if "rewards" in kwargs:
            quest.rewards = kwargs["rewards"]
        if "notes" in kwargs:
            quest.notes = kwargs["notes"]

        quest.updated_at = _now_iso()
        result = self._db.update_quest(quest)
        self._event_bus.publish(
            f"quest:{quest_id}", EventType.QUEST_UPDATED.value,
            {"quest_id": quest_id, "updates": list(kwargs.keys())}, user_id
        )
        return result

    def update_status(self, quest_id: str, user_id: str, new_status: str) -> Quest:
        quest = self._db.get_quest(quest_id)
        if quest.owner_id != user_id and user_id not in quest.collaborator_ids:
            raise AuthorizationError("You don't have permission to update this quest")

        if new_status not in [s.value for s in QuestStatus]:
            raise ValidationError(f"Invalid status: {new_status}")

        valid_transitions = {
            QuestStatus.DRAFT.value: [QuestStatus.ACTIVE.value, QuestStatus.ABANDONED.value],
            QuestStatus.ACTIVE.value: [QuestStatus.IN_PROGRESS.value, QuestStatus.ABANDONED.value],
            QuestStatus.IN_PROGRESS.value: [QuestStatus.COMPLETED.value, QuestStatus.FAILED.value, QuestStatus.ABANDONED.value],
            QuestStatus.COMPLETED.value: [],
            QuestStatus.FAILED.value: [QuestStatus.ACTIVE.value],
            QuestStatus.ABANDONED.value: [QuestStatus.ACTIVE.value],
        }

        if new_status not in valid_transitions.get(quest.status, []):
            raise ValidationError(
                f"Cannot transition from '{quest.status}' to '{new_status}'"
            )

        quest.status = new_status
        quest.updated_at = _now_iso()
        if new_status == QuestStatus.COMPLETED.value:
            quest.completed_at = _now_iso()
            quest.progress = 100.0

        result = self._db.update_quest(quest)
        if new_status == QuestStatus.COMPLETED.value:
            self._event_bus.publish(
                f"quest:{quest_id}", EventType.QUEST_COMPLETED.value,
                {"quest_id": quest_id}, user_id
            )
        return result

    def complete_objective(self, quest_id: str, user_id: str, objective_id: str) -> Quest:
        quest = self._db.get_quest(quest_id)
        if quest.owner_id != user_id and user_id not in quest.collaborator_ids:
            raise AuthorizationError("You don't have permission to update this quest")

        found = False
        for obj in quest.objectives:
            if obj["id"] == objective_id:
                obj["is_completed"] = True
                obj["completed_at"] = _now_iso()
                found = True
                break

        if not found:
            raise NotFoundError(f"Objective '{objective_id}' not found")

        completed = sum(1 for o in quest.objectives if o["is_completed"])
        total = len(quest.objectives)
        quest.progress = (completed / total * 100.0) if total > 0 else 0.0
        quest.updated_at = _now_iso()

        result = self._db.update_quest(quest)
        self._event_bus.publish(
            f"quest:{quest_id}", EventType.QUEST_UPDATED.value,
            {"quest_id": quest_id, "objective_completed": objective_id,
             "progress": quest.progress}, user_id
        )
        return result

    def delete_quest(self, quest_id: str, user_id: str) -> None:
        quest = self._db.get_quest(quest_id)
        if quest.owner_id != user_id:
            raise AuthorizationError("Only the quest owner can delete a quest")
        self._db.delete_quest(quest_id)
        self._event_bus.publish(
            f"user:{user_id}", EventType.QUEST_DELETED.value,
            {"quest_id": quest_id}, user_id
        )

    def list_quests(self, owner_id: Optional[str] = None, status: Optional[str] = None,
                    tag: Optional[str] = None, offset: int = 0, limit: int = 50) -> list[Quest]:
        return self._db.list_quests(owner_id, status, tag, offset, limit)

    def search_quests(self, query: str, offset: int = 0, limit: int = 50) -> list[Quest]:
        return self._db.search_quests(query, offset, limit)

    def add_collaborator(self, quest_id: str, owner_id: str, collaborator_id: str) -> Quest:
        quest = self._db.get_quest(quest_id)
        if quest.owner_id != owner_id:
            raise AuthorizationError("Only the quest owner can add collaborators")
        self._db.get_user(collaborator_id)
        if collaborator_id in quest.collaborator_ids:
            raise ConflictError("User is already a collaborator")
        if collaborator_id == owner_id:
            raise ValidationError("Owner cannot be added as collaborator")
        quest.collaborator_ids.append(collaborator_id)
        quest.updated_at = _now_iso()
        result = self._db.update_quest(quest)
        self._event_bus.publish(
            f"quest:{quest_id}", EventType.COLLABORATOR_JOINED.value,
            {"quest_id": quest_id, "user_id": collaborator_id}, owner_id
        )
        return result

    def remove_collaborator(self, quest_id: str, owner_id: str, collaborator_id: str) -> Quest:
        quest = self._db.get_quest(quest_id)
        if quest.owner_id != owner_id:
            raise AuthorizationError("Only the quest owner can remove collaborators")
        if collaborator_id not in quest.collaborator_ids:
            raise NotFoundError("User is not a collaborator")
        quest.collaborator_ids.remove(collaborator_id)
        quest.updated_at = _now_iso()
        result = self._db.update_quest(quest)
        self._event_bus.publish(
            f"quest:{quest_id}", EventType.COLLABORATOR_LEFT.value,
            {"quest_id": quest_id, "user_id": collaborator_id}, owner_id
        )
        return result


class SkillPlanService:
    """Manages character skill plans."""

    def __init__(self, db: Database, event_bus: EventBus):
        self._db = db
        self._lock = db.lock
        self._event_bus = event_bus

    def create_plan(self, owner_id: str, name: str, character_name: str = "",
                    character_class: str = "", target_level: int = 50,
                    is_public: bool = False) -> SkillPlan:
        self._db.get_user(owner_id)
        if not name or len(name.strip()) == 0:
            raise ValidationError("Plan name is required")
        if target_level < 1 or target_level > 100:
            raise ValidationError("Target level must be between 1 and 100")

        now = _now_iso()
        plan = SkillPlan(
            id=str(uuid.uuid4()),
            name=name.strip(),
            owner_id=owner_id,
            character_name=character_name,
            character_class=character_class,
            target_level=target_level,
            is_public=is_public,
            created_at=now,
            updated_at=now,
        )
        return self._db.create_skill_plan(plan)

    def get_plan(self, plan_id: str, user_id: Optional[str] = None) -> SkillPlan:
        plan = self._db.get_skill_plan(plan_id)
        if not plan.is_public and user_id:
            if plan.owner_id != user_id and user_id not in plan.collaborator_ids:
                raise AuthorizationError("You don't have access to this skill plan")
        return plan

    def update_plan(self, plan_id: str, user_id: str, **kwargs) -> SkillPlan:
        plan = self._db.get_skill_plan(plan_id)
        if plan.owner_id != user_id and user_id not in plan.collaborator_ids:
            raise AuthorizationError("You don't have permission to update this plan")

        if "name" in kwargs:
            if not kwargs["name"] or len(kwargs["name"].strip()) == 0:
                raise ValidationError("Plan name is required")
            plan.name = kwargs["name"].strip()
        if "character_name" in kwargs:
            plan.character_name = kwargs["character_name"]
        if "character_class" in kwargs:
            plan.character_class = kwargs["character_class"]
        if "target_level" in kwargs:
            tl = kwargs["target_level"]
            if tl < 1 or tl > 100:
                raise ValidationError("Target level must be between 1 and 100")
            plan.target_level = tl
        if "is_public" in kwargs:
            plan.is_public = kwargs["is_public"]
        if "notes" in kwargs:
            plan.notes = kwargs["notes"]
        if "milestones" in kwargs:
            plan.milestones = kwargs["milestones"]

        plan.updated_at = _now_iso()
        result = self._db.update_skill_plan(plan)
        self._event_bus.publish(
            f"plan:{plan_id}", EventType.PLAN_UPDATED.value,
            {"plan_id": plan_id, "updates": list(kwargs.keys())}, user_id
        )
        return result

    def add_skill(self, plan_id: str, user_id: str, name: str,
                  category: str, description: str = "",
                  current_level: int = 0, max_level: int = 100,
                  prerequisites: Optional[list] = None) -> SkillPlan:
        plan = self._db.get_skill_plan(plan_id)
        if plan.owner_id != user_id and user_id not in plan.collaborator_ids:
            raise AuthorizationError("You don't have permission to modify this plan")

        if not name or len(name.strip()) == 0:
            raise ValidationError("Skill name is required")
        if category not in [c.value for c in SkillCategory]:
            raise ValidationError(f"Invalid skill category: {category}")
        if current_level < 0 or current_level > max_level:
            raise ValidationError("Invalid skill level")

        for existing in plan.skills:
            if existing["name"].lower() == name.lower():
                raise ConflictError(f"Skill '{name}' already exists in this plan")

        skill = {
            "id": str(uuid.uuid4()),
            "name": name.strip(),
            "category": category,
            "description": description,
            "current_level": current_level,
            "max_level": max_level,
            "experience": 0,
            "experience_to_next": 100 * (current_level + 1),
            "prerequisites": prerequisites or [],
            "bonuses": {},
        }
        plan.skills.append(skill)
        plan.updated_at = _now_iso()
        result = self._db.update_skill_plan(plan)
        self._event_bus.publish(
            f"plan:{plan_id}", EventType.SKILL_ADDED.value,
            {"plan_id": plan_id, "skill": skill["name"]}, user_id
        )
        return result

    def update_skill(self, plan_id: str, user_id: str, skill_id: str, **kwargs) -> SkillPlan:
        plan = self._db.get_skill_plan(plan_id)
        if plan.owner_id != user_id and user_id not in plan.collaborator_ids:
            raise AuthorizationError("You don't have permission to modify this plan")

        skill = None
        for s in plan.skills:
            if s["id"] == skill_id:
                skill = s
                break
        if skill is None:
            raise NotFoundError(f"Skill '{skill_id}' not found in plan")

        if "current_level" in kwargs:
            lvl = kwargs["current_level"]
            if lvl < 0 or lvl > skill["max_level"]:
                raise ValidationError("Invalid skill level")
            skill["current_level"] = lvl
            skill["experience_to_next"] = 100 * (lvl + 1)
        if "experience" in kwargs:
            skill["experience"] = kwargs["experience"]
        if "description" in kwargs:
            skill["description"] = kwargs["description"]
        if "bonuses" in kwargs:
            skill["bonuses"] = kwargs["bonuses"]

        plan.updated_at = _now_iso()
        result = self._db.update_skill_plan(plan)
        self._event_bus.publish(
            f"plan:{plan_id}", EventType.SKILL_UPDATED.value,
            {"plan_id": plan_id, "skill_id": skill_id}, user_id
        )
        return result

    def remove_skill(self, plan_id: str, user_id: str, skill_id: str) -> SkillPlan:
        plan = self._db.get_skill_plan(plan_id)
        if plan.owner_id != user_id and user_id not in plan.collaborator_ids:
            raise AuthorizationError("You don't have permission to modify this plan")

        original_len = len(plan.skills)
        plan.skills = [s for s in plan.skills if s["id"] != skill_id]
        if len(plan.skills) == original_len:
            raise NotFoundError(f"Skill '{skill_id}' not found in plan")

        plan.updated_at = _now_iso()
        result = self._db.update_skill_plan(plan)
        self._event_bus.publish(
            f"plan:{plan_id}", EventType.SKILL_REMOVED.value,
            {"plan_id": plan_id, "skill_id": skill_id}, user_id
        )
        return result

    def delete_plan(self, plan_id: str, user_id: str) -> None:
        plan = self._db.get_skill_plan(plan_id)
        if plan.owner_id != user_id:
            raise AuthorizationError("Only the plan owner can delete it")
        self._db.delete_skill_plan(plan_id)

    def list_plans(self, owner_id: Optional[str] = None,
                   offset: int = 0, limit: int = 50) -> list[SkillPlan]:
        return self._db.list_skill_plans(owner_id, offset, limit)

    def add_collaborator(self, plan_id: str, owner_id: str, collaborator_id: str) -> SkillPlan:
        plan = self._db.get_skill_plan(plan_id)
        if plan.owner_id != owner_id:
            raise AuthorizationError("Only the plan owner can add collaborators")
        self._db.get_user(collaborator_id)
        if collaborator_id in plan.collaborator_ids:
            raise ConflictError("User is already a collaborator")
        if collaborator_id == owner_id:
            raise ValidationError("Owner cannot be added as collaborator")
        plan.collaborator_ids.append(collaborator_id)
        plan.updated_at = _now_iso()
        return self._db.update_skill_plan(plan)

    def remove_collaborator(self, plan_id: str, owner_id: str, collaborator_id: str) -> SkillPlan:
        plan = self._db.get_skill_plan(plan_id)
        if plan.owner_id != owner_id:
            raise AuthorizationError("Only the plan owner can remove collaborators")
        if collaborator_id not in plan.collaborator_ids:
            raise NotFoundError("User is not a collaborator")
        plan.collaborator_ids.remove(collaborator_id)
        plan.updated_at = _now_iso()
        return self._db.update_skill_plan(plan)


class CollaborationService:
    """Manages real-time collaboration sessions."""

    def __init__(self, db: Database, event_bus: EventBus):
        self._db = db
        self._lock = db.lock
        self._event_bus = event_bus

    def create_or_join_session(self, resource_type: str, resource_id: str,
                               user_id: str, role: str = CollaborationRole.EDITOR.value) -> CollaborationSession:
        self._db.get_user(user_id)
        if resource_type not in ("quest", "skill_plan"):
            raise ValidationError("Resource type must be 'quest' or 'skill_plan'")

        if resource_type == "quest":
            quest = self._db.get_quest(resource_id)
            if quest.owner_id != user_id and user_id not in quest.collaborator_ids:
                raise AuthorizationError("You don't have access to this quest")
        else:
            plan = self._db.get_skill_plan(resource_id)
            if plan.owner_id != user_id and user_id not in plan.collaborator_ids:
                if not plan.is_public:
                    raise AuthorizationError("You don't have access to this skill plan")
                role = CollaborationRole.VIEWER.value

        existing = self._db.find_collaboration_session(resource_type, resource_id)
        if existing:
            if user_id not in existing.participants:
                existing.participants[user_id] = role
                existing.updated_at = _now_iso()
                result = self._db.update_collaboration_session(existing)
                self._event_bus.publish(
                    f"collab:{existing.id}", EventType.COLLABORATOR_JOINED.value,
                    {"session_id": existing.id, "user_id": user_id, "role": role}, user_id
                )
                return result
            return existing

        now = _now_iso()
        session = CollaborationSession(
            id=str(uuid.uuid4()),
            resource_type=resource_type,
            resource_id=resource_id,
            owner_id=user_id,
            participants={user_id: CollaborationRole.OWNER.value},
            created_at=now,
            updated_at=now,
        )
        result = self._db.create_collaboration_session(session)
        self._event_bus.publish(
            f"collab:{result.id}", EventType.COLLABORATOR_JOINED.value,
            {"session_id": result.id, "user_id": user_id, "role": "owner"}, user_id
        )
        return result

    def leave_session(self, session_id: str, user_id: str) -> None:
        session = self._db.get_collaboration_session(session_id)
        if user_id not in session.participants:
            raise NotFoundError("User is not in this session")
        del session.participants[user_id]
        session.updated_at = _now_iso()
        if not session.participants:
            session.is_active = False
        self._db.update_collaboration_session(session)
        self._event_bus.publish(
            f"collab:{session_id}", EventType.COLLABORATOR_LEFT.value,
            {"session_id": session_id, "user_id": user_id}, user_id
        )

    def send_message(self, session_id: str, sender_id: str, content: str,
                     message_type: str = "text") -> Message:
        session = self._db.get_collaboration_session(session_id)
        if sender_id not in session.participants:
            raise AuthorizationError("You are not in this collaboration session")
        if not content or len(content.strip()) == 0:
            raise ValidationError("Message content is required")

        message = Message(
            id=str(uuid.uuid4()),
            session_id=session_id,
            sender_id=sender_id,
            content=content.strip(),
            message_type=message_type,
            timestamp=_now_iso(),
        )
        result = self._db.add_message(message)
        self._event_bus.publish(
            f"collab:{session_id}", EventType.MESSAGE_SENT.value,
            {"message_id": result.id, "sender_id": sender_id,
             "content": result.content, "type": message_type}, sender_id
        )
        return result

    def get_messages(self, session_id: str, user_id: str,
                     offset: int = 0, limit: int = 100) -> list[Message]:
        session = self._db.get_collaboration_session(session_id)
        if user_id not in session.participants:
            raise AuthorizationError("You are not in this collaboration session")
        return self._db.get_messages(session_id, offset, limit)

    def get_session(self, session_id: str) -> CollaborationSession:
        return self._db.get_collaboration_session(session_id)

    def get_active_sessions(self, user_id: str) -> list[CollaborationSession]:
        with self._lock:
            sessions = []
            for s in self._db._collaboration_sessions.values():
                if s.is_active and user_id in s.participants:
                    sessions.append(copy.deepcopy(s))
            return sessions


