class QuestHub:
    """Main application class integrating all services."""

    def __init__(self):
        self.db = Database()
        self.event_bus = EventBus()
        self.auth = AuthService(self.db)
        self.quests = QuestService(self.db, self.event_bus)
        self.skill_plans = SkillPlanService(self.db, self.event_bus)
        self.collaboration = CollaborationService(self.db, self.event_bus)

    def get_dashboard(self, user_id: str) -> dict:
        """Get a user's dashboard with all relevant data."""
        user = self.db.get_user(user_id)
        quests = self.quests.list_quests(owner_id=user_id)
        plans = self.skill_plans.list_plans(owner_id=user_id)
        active_sessions = self.collaboration.get_active_sessions(user_id)

        active_quests = [q for q in quests if q.status in (QuestStatus.ACTIVE.value, QuestStatus.IN_PROGRESS.value)]
        completed_quests = [q for q in quests if q.status == QuestStatus.COMPLETED.value]

        total_skills = sum(len(p.skills) for p in plans)
        avg_skill_level = 0.0
        if total_skills > 0:
            total_level = sum(
                s["current_level"] for p in plans for s in p.skills
            )
            avg_skill_level = total_level / total_skills

        return {
            "user": user.to_public_dict(),
            "stats": {
                "total_quests": len(quests),
                "active_quests": len(active_quests),
                "completed_quests": len(completed_quests),
                "total_skill_plans": len(plans),
                "total_skills": total_skills,
                "average_skill_level": round(avg_skill_level, 1),
                "active_collaborations": len(active_sessions),
            },
            "recent_quests": [q.to_dict() for q in quests[:5]],
            "active_collaborations": [s.to_dict() for s in active_sessions[:5]],
        }

    def export_data(self, user_id: str, format: str = "json") -> str:
        """Export user data in specified format."""
        user = self.db.get_user(user_id)
        quests = self.quests.list_quests(owner_id=user_id, limit=1000)
        plans = self.skill_plans.list_plans(owner_id=user_id)

        if format == "json":
            data = {
                "user": user.to_public_dict(),
                "quests": [q.to_dict() for q in quests],
                "skill_plans": [p.to_dict() for p in plans],
                "exported_at": _now_iso(),
            }
            return json.dumps(data, indent=2)
        elif format == "csv":
            output = io.StringIO()
            writer = csv.writer(output)
            writer.writerow(["Type", "ID", "Name", "Status", "Created"])
            for q in quests:
                writer.writerow(["quest", q.id, q.title, q.status, q.created_at])
            for p in plans:
                writer.writerow(["skill_plan", p.id, p.name, "", p.created_at])
            return output.getvalue()
        else:
            raise ValidationError(f"Unsupported export format: {format}")


# ==============================================================================
# HTTP API LAYER
# ==============================================================================

class APIHandler(BaseHTTPRequestHandler):
    """RESTful API request handler."""

    hub: QuestHub = None  # Set by server

    def log_message(self, format, *args):
        pass  # Suppress default logging

    def _send_json(self, data: Any, status: int = 200):
        body = json.dumps(data, default=str).encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(body)))
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type, Authorization")
        self.end_headers()
        self.wfile.write(body)

    def _send_error(self, message: str, status: int = 400):
        self._send_json({"error": message}, status)

    def _send_html(self, html_content: str, status: int = 200):
        body = html_content.encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "text/html; charset=utf-8")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def _get_body(self) -> dict:
        content_length = int(self.headers.get("Content-Length", 0))
        if content_length == 0:
            return {}
        body = self.rfile.read(content_length)
        try:
            return json.loads(body)
        except json.JSONDecodeError:
            raise ValidationError("Invalid JSON body")

    def _get_token(self) -> str:
        auth_header = self.headers.get("Authorization", "")
        if auth_header.startswith("Bearer "):
            return auth_header[7:]
        return ""

    def _authenticate(self) -> User:
        token = self._get_token()
        return self.hub.auth.authenticate(token)

    def _route(self, method: str):
        parsed = urlparse(self.path)
        path = parsed.path.rstrip("/")
        params = parse_qs(parsed.query)

        try:
            # Frontend
            if path == "" or path == "/":
                self._send_html(get_frontend_html())
                return

            # Auth routes
            if path == "/api/auth/register" and method == "POST":
                return self._handle_register()
            if path == "/api/auth/login" and method == "POST":
                return self._handle_login()
            if path == "/api/auth/logout" and method == "POST":
                return self._handle_logout()
            if path == "/api/auth/me" and method == "GET":
                return self._handle_me()

            # Quest routes
            if path == "/api/quests" and method == "GET":
                return self._handle_list_quests(params)
            if path == "/api/quests" and method == "POST":
                return self._handle_create_quest()
            if path == "/api/quests/search" and method == "GET":
                return self._handle_search_quests(params)
            if path.startswith("/api/quests/") and method == "GET":
                quest_id = path.split("/")[3]
                return self._handle_get_quest(quest_id)
            if path.startswith("/api/quests/") and method == "PUT":
                quest_id = path.split("/")[3]
                if path.endswith("/status"):
                    return self._handle_update_quest_status(quest_id)
                if path.endswith("/objectives"):
                    parts = path.split("/")
                    return self._handle_complete_objective(parts[3])
                return self._handle_update_quest(quest_id)
            if path.startswith("/api/quests/") and method == "DELETE":
                quest_id = path.split("/")[3]
                return self._handle_delete_quest(quest_id)
            if path.startswith("/api/quests/") and path.endswith("/collaborators") and method == "POST":
                quest_id = path.split("/")[3]
                return self._handle_add_quest_collaborator(quest_id)

            # Skill plan routes
            if path == "/api/plans" and method == "GET":
                return self._handle_list_plans(params)
            if path == "/api/plans" and method == "POST":
                return self._handle_create_plan()
            if path.startswith("/api/plans/") and method == "GET":
                plan_id = path.split("/")[3]
                return self._handle_get_plan(plan_id)
            if path.startswith("/api/plans/") and method == "PUT":
                plan_id = path.split("/")[3]
                return self._handle_update_plan(plan_id)
            if path.startswith("/api/plans/") and method == "DELETE":
                plan_id = path.split("/")[3]
                return self._handle_delete_plan(plan_id)
            if path.startswith("/api/plans/") and path.endswith("/skills") and method == "POST":
                plan_id = path.split("/")[3]
                return self._handle_add_skill(plan_id)
            if path.startswith("/api/plans/") and "/skills/" in path and method == "PUT":
                parts = path.split("/")
                return self._handle_update_skill(parts[3], parts[5])
            if path.startswith("/api/plans/") and "/skills/" in path and method == "DELETE":
                parts = path.split("/")
                return self._handle_remove_skill(parts[3], parts[5])

            # Collaboration routes
            if path == "/api/collaboration/sessions" and method == "POST":
                return self._handle_join_session()
            if path.startswith("/api/collaboration/sessions/") and path.endswith("/messages") and method == "POST":
                session_id = path.split("/")[4]
                return self._handle_send_message(session_id)
            if path.startswith("/api/collaboration/sessions/") and path.endswith("/messages") and method == "GET":
                session_id = path.split("/")[4]
                return self._handle_get_messages(session_id, params)
            if path.startswith("/api/collaboration/sessions/") and path.endswith("/leave") and method == "POST":
                session_id = path.split("/")[4]
                return self._handle_leave_session(session_id)

            # Dashboard & export
            if path == "/api/dashboard" and method == "GET":
                return self._handle_dashboard()
            if path == "/api/export" and method == "GET":
                return self._handle_export(params)

            # Stats
            if path == "/api/stats" and method == "GET":
                return self._handle_stats()

            # Events
            if path == "/api/events" and method == "GET":
                return self._handle_events(params)

            self._send_error("Not found", 404)

        except AuthenticationError as e:
            self._send_error(str(e), 401)
        except AuthorizationError as e:
            self._send_error(str(e), 403)
        except NotFoundError as e:
            self._send_error(str(e), 404)
        except ConflictError as e:
            self._send_error(str(e), 409)
        except ValidationError as e:
            self._send_error(str(e), 422)
        except Exception as e:
            self._send_error(f"Internal server error: {str(e)}", 500)

    # --- Auth handlers ---

    def _handle_register(self):
        body = self._get_body()
        user = self.hub.auth.register(
            username=body.get("username", ""),
            email=body.get("email", ""),
            password=body.get("password", ""),
            display_name=body.get("display_name", ""),
        )
        self._send_json({"user": user.to_public_dict()}, 201)

    def _handle_login(self):
        body = self._get_body()
        user, token = self.hub.auth.login(
            body.get("username", body.get("email", "")),
            body.get("password", ""),
        )
        self._send_json({"user": user.to_public_dict(), "token": token})

    def _handle_logout(self):
        token = self._get_token()
        self.hub.auth.logout(token)
        self._send_json({"message": "Logged out"})

    def _handle_me(self):
        user = self._authenticate()
        self._send_json({"user": user.to_public_dict()})

    # --- Quest handlers ---

    def _handle_list_quests(self, params):
        user = self._authenticate()
        quests = self.hub.quests.list_quests(
            owner_id=params.get("owner_id", [user.id])[0],
            status=params.get("status", [None])[0],
            tag=params.get("tag", [None])[0],
            offset=int(params.get("offset", [0])[0]),
            limit=int(params.get("limit", [50])[0]),
        )
        self._send_json({"quests": [q.to_dict() for q in quests]})

    def _handle_create_quest(self):
        user = self._authenticate()
        body = self._get_body()
        quest = self.hub.quests.create_quest(
            owner_id=user.id,
            title=body.get("title", ""),
            description=body.get("description", ""),
            difficulty=body.get("difficulty", QuestDifficulty.MEDIUM.value),
            objectives=body.get("objectives"),
            rewards=body.get("rewards"),
            tags=body.get("tags"),
            deadline=body.get("deadline"),
            parent_quest_id=body.get("parent_quest_id"),
        )
        self._send_json({"quest": quest.to_dict()}, 201)

    def _handle_get_quest(self, quest_id):
        user = self._authenticate()
        quest = self.hub.quests.get_quest(quest_id, user.id)
        self._send_json({"quest": quest.to_dict()})

    def _handle_update_quest(self, quest_id):
        user = self._authenticate()
        body = self._get_body()
        quest = self.hub.quests.update_quest(quest_id, user.id, **body)
        self._send_json({"quest": quest.to_dict()})

    def _handle_update_quest_status(self, quest_id):
        user = self._authenticate()
        body = self._get_body()
        quest = self.hub.quests.update_status(quest_id, user.id, body.get("status", ""))
        self._send_json({"quest": quest.to_dict()})

    def _handle_complete_objective(self, quest_id):
        user = self._authenticate()
        body = self._get_body()
        quest = self.hub.quests.complete_objective(quest_id, user.id, body.get("objective_id", ""))
        self._send_json({"quest": quest.to_dict()})

    def _handle_delete_quest(self, quest_id):
        user = self._authenticate()
        self.hub.quests.delete_quest(quest_id, user.id)
        self._send_json({"message": "Quest deleted"})

    def _handle_search_quests(self, params):
        self._authenticate()
        quests = self.hub.quests.search_quests(
            query=params.get("q", [""])[0],
            offset=int(params.get("offset", [0])[0]),
            limit=int(params.get("limit", [50])[0]),
        )
        self._send_json({"quests": [q.to_dict() for q in quests]})

    def _handle_add_quest_collaborator(self, quest_id):
        user = self._authenticate()
        body = self._get_body()
        quest = self.hub.quests.add_collaborator(quest_id, user.id, body.get("user_id", ""))
        self._send_json({"quest": quest.to_dict()})

    # --- Skill plan handlers ---

    def _handle_list_plans(self, params):
        user = self._authenticate()
        plans = self.hub.skill_plans.list_plans(
            owner_id=params.get("owner_id", [user.id])[0],
            offset=int(params.get("offset", [0])[0]),
            limit=int(params.get("limit", [50])[0]),
        )
        self._send_json({"plans": [p.to_dict() for p in plans]})

    def _handle_create_plan(self):
        user = self._authenticate()
        body = self._get_body()
        plan = self.hub.skill_plans.create_plan(
            owner_id=user.id,
            name=body.get("name", ""),
            character_name=body.get("character_name", ""),
            character_class=body.get("character_class", ""),
            target_level=body.get("target_level", 50),
            is_public=body.get("is_public", False),
        )
        self._send_json({"plan": plan.to_dict()}, 201)

    def _handle_get_plan(self, plan_id):
        user = self._authenticate()
        plan = self.hub.skill_plans.get_plan(plan_id, user.id)
        self._send_json({"plan": plan.to_dict()})

    def _handle_update_plan(self, plan_id):
        user = self._authenticate()
        body = self._get_body()
        plan = self.hub.skill_plans.update_plan(plan_id, user.id, **body)
        self._send_json({"plan": plan.to_dict()})

    def _handle_delete_plan(self, plan_id):
        user = self._authenticate()
        self.hub.skill_plans.delete_plan(plan_id, user.id)
        self._send_json({"message": "Skill plan deleted"})

    def _handle_add_skill(self, plan_id):
        user = self._authenticate()
        body = self._get_body()
        plan = self.hub.skill_plans.add_skill(
            plan_id=plan_id,
            user_id=user.id,
            name=body.get("name", ""),
            category=body.get("category", ""),
            description=body.get("description", ""),
            current_level=body.get("current_level", 0),
            max_level=body.get("max_level", 100),
            prerequisites=body.get("prerequisites"),
        )
        self._send_json({"plan": plan.to_dict()})

    def _handle_update_skill(self, plan_id, skill_id):
        user = self._authenticate()
        body = self._get_body()
        plan = self.hub.skill_plans.update_skill(plan_id, user.id, skill_id, **body)
        self._send_json({"plan": plan.to_dict()})

    def _handle_remove_skill(self, plan_id, skill_id):
        user = self._authenticate()
        plan = self.hub.skill_plans.remove_skill(plan_id, user.id, skill_id)
        self._send_json({"plan": plan.to_dict()})

    # --- Collaboration handlers ---

    def _handle_join_session(self):
        user = self._authenticate()
        body = self._get_body()
        session = self.hub.collaboration.create_or_join_session(
            resource_type=body.get("resource_type", ""),
            resource_id=body.get("resource_id", ""),
            user_id=user.id,
            role=body.get("role", CollaborationRole.EDITOR.value),
        )
        self._send_json({"session": session.to_dict()}, 201)

    def _handle_send_message(self, session_id):
        user = self._authenticate()
        body = self._get_body()
        message = self.hub.collaboration.send_message(
            session_id=session_id,
            sender_id=user.id,
            content=body.get("content", ""),
            message_type=body.get("type", "text"),
        )
        self._send_json({"message": {
            "id": message.id,
            "session_id": message.session_id,
            "sender_id": message.sender_id,
            "content": message.content,
            "type": message.message_type,
            "timestamp": message.timestamp,
        }}, 201)

    def _handle_get_messages(self, session_id, params):
        user = self._authenticate()
        messages = self.hub.collaboration.get_messages(
            session_id=session_id,
            user_id=user.id,
            offset=int(params.get("offset", [0])[0]),
            limit=int(params.get("limit", [100])[0]),
        )
        self._send_json({"messages": [
            {"id": m.id, "session_id": m.session_id, "sender_id": m.sender_id,
             "content": m.content, "type": m.message_type, "timestamp": m.timestamp}
            for m in messages
        ]})

    def _handle_leave_session(self, session_id):
        user = self._authenticate()
        self.hub.collaboration.leave_session(session_id, user.id)
        self._send_json({"message": "Left session"})

    # --- Dashboard & utility handlers ---

    def _handle_dashboard(self):
        user = self._authenticate()
        dashboard = self.hub.get_dashboard(user.id)
        self._send_json(dashboard)

    def _handle_export(self, params):
        user = self._authenticate()
        fmt = params.get("format", ["json"])[0]
        data = self.hub.export_data(user.id, fmt)
        if fmt == "csv":
            body = data.encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "text/csv")
            self.send_header("Content-Disposition", "attachment; filename=questhub_export.csv")
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)
        else:
            self._send_json(json.loads(data))

    def _handle_stats(self):
        stats = self.hub.db.get_stats()
        self._send_json(stats)

    def _handle_events(self, params):
        user = self._authenticate()
        channel = params.get("channel", [f"user:{user.id}"])[0]
        limit = int(params.get("limit", [50])[0])
        events = self.hub.event_bus.get_recent_events(channel, limit)
        self._send_json({"events": events})

    # --- HTTP method dispatchers ---

    def do_GET(self):
        self._route("GET")

    def do_POST(self):
        self._route("POST")

    def do_PUT(self):
        self._route("PUT")

    def do_DELETE(self):
        self._route("DELETE")

    def do_OPTIONS(self):
        self.send_response(200)
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type, Authorization")
        self.end_headers()


