    </style>
</head>
<body>
    <div class="container">
        <header>
            <h1>&#9876; QuestHub</h1>
            <p>Manage quests, plan skills, collaborate with your party</p>
            <div class="nav" id="main-nav">
                <button class="active" onclick="showSection('dashboard')">Dashboard</button>
                <button onclick="showSection('quests')">Quests</button>
                <button onclick="showSection('skills')">Skill Plans</button>
                <button onclick="showSection('collab')">Collaboration</button>
                <button onclick="logout()" style="margin-left:auto;background:#c0392b;">Logout</button>
            </div>
        </header>

        <!-- Auth Section -->
        <div id="auth-section">
            <div class="card">
                <h3>Login to QuestHub</h3>
                <div class="form-group">
                    <label>Username or Email</label>
                    <input type="text" id="login-user" placeholder="Enter username or email">
                </div>
                <div class="form-group">
                    <label>Password</label>
                    <input type="password" id="login-pass" placeholder="Enter password">
                </div>
                <button class="btn btn-primary" onclick="login()">Login</button>
                <button class="btn btn-secondary" onclick="showRegister()" style="margin-left:10px;">Register</button>
                <div id="login-error" style="color:#e94560;margin-top:10px;"></div>
            </div>
        </div>

        <!-- App Section -->
        <div id="app-section" class="hidden">
            <div id="section-dashboard"></div>
            <div id="section-quests" class="hidden"></div>
            <div id="section-skills" class="hidden"></div>
            <div id="section-collab" class="hidden"></div>
        </div>
    </div>

    <script>
    let token = localStorage.getItem('qh_token');
    let currentUser = null;

    const API = '';

    async function api(path, opts = {}) {
        const headers = {'Content-Type': 'application/json'};
        if (token) headers['Authorization'] = 'Bearer ' + token;
        const res = await fetch(API + path, {...opts, headers});
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Request failed');
        return data;
    }

    async function login() {
        try {
            const data = await api('/api/auth/login', {
                method: 'POST',
                body: JSON.stringify({
                    username: document.getElementById('login-user').value,
                    password: document.getElementById('login-pass').value
                })
            });
            token = data.token;
            currentUser = data.user;
            localStorage.setItem('qh_token', token);
            showApp();
        } catch(e) {
            document.getElementById('login-error').textContent = e.message;
        }
    }

    function logout() {
        token = null;
        currentUser = null;
        localStorage.removeItem('qh_token');
        document.getElementById('auth-section').classList.remove('hidden');
        document.getElementById('app-section').classList.add('hidden');
    }

    async function showApp() {
        document.getElementById('auth-section').classList.add('hidden');
        document.getElementById('app-section').classList.remove('hidden');
        await loadDashboard();
    }

    async function loadDashboard() {
        try {
            const data = await api('/api/dashboard');
            const s = data.stats;
            document.getElementById('section-dashboard').innerHTML = `
                <div class="stats-grid">
                    <div class="stat-card"><div class="value">${s.total_quests}</div><div class="label">Total Quests</div></div>
                    <div class="stat-card"><div class="value">${s.active_quests}</div><div class="label">Active Quests</div></div>
                    <div class="stat-card"><div class="value">${s.completed_quests}</div><div class="label">Completed</div></div>
                    <div class="stat-card"><div class="value">${s.total_skill_plans}</div><div class="label">Skill Plans</div></div>
                    <div class="stat-card"><div class="value">${s.average_skill_level}</div><div class="label">Avg Skill Level</div></div>
                    <div class="stat-card"><div class="value">${s.active_collaborations}</div><div class="label">Active Collabs</div></div>
                </div>
                <div class="card" style="margin-top:20px;">
                    <h3>Recent Quests</h3>
                    <ul class="quest-list">
                        ${data.recent_quests.map(q => `
                            <li class="quest-item">
                                <div><strong>${q.title}</strong><br><small>${q.description.substring(0,80)}</small></div>
                                <span class="badge badge-${q.status}">${q.status}</span>
                            </li>
                        `).join('')}
                        ${data.recent_quests.length === 0 ? '<li class="quest-item">No quests yet. Create your first quest!</li>' : ''}
                    </ul>
                </div>`;
        } catch(e) { console.error(e); }
    }

    function showSection(name) {
        ['dashboard','quests','skills','collab'].forEach(s => {
            document.getElementById('section-' + s).classList.add('hidden');
        });
        document.getElementById('section-' + name).classList.remove('hidden');
        document.querySelectorAll('.nav button').forEach(b => b.classList.remove('active'));
        event.target.classList.add('active');
        if (name === 'dashboard') loadDashboard();
