def run_smoke_test():
    """Run a comprehensive smoke test to verify all functionality."""
    print("Running QuestHub smoke test...")

    hub = QuestHub()

    # Test user registration
    user1 = hub.auth.register("hero_knight", "knight@realm.com", "sword123", "Sir Knight")
    user2 = hub.auth.register("dark_mage", "mage@realm.com", "magic456", "Dark Mage")
    assert user1.username == "hero_knight"
    assert user2.username == "dark_mage"
    print("  [PASS] User registration")

    # Test login
    logged_user, token = hub.auth.login("hero_knight", "sword123")
    assert logged_user.id == user1.id
    assert token
    print("  [PASS] User login")

    # Test authentication
    auth_user = hub.auth.authenticate(token)
    assert auth_user.id == user1.id
    print("  [PASS] Token authentication")

    # Test quest creation
    quest = hub.quests.create_quest(
        owner_id=user1.id,
        title="Defeat the Dragon",
        description="Slay the ancient dragon terrorizing the village",
        difficulty="hard",
        objectives=["Find the dragon's lair", "Acquire fire-resistant armor", "Defeat the dragon"],
        rewards={"gold": 1000, "xp": 5000},
        tags=["combat", "boss", "epic"],
    )
    assert quest.title == "Defeat the Dragon"
    assert len(quest.objectives) == 3
    assert quest.status == "draft"
    print("  [PASS] Quest creation")

    # Test quest status transitions
    quest = hub.quests.update_status(quest.id, user1.id, "active")
    assert quest.status == "active"
    quest = hub.quests.update_status(quest.id, user1.id, "in_progress")
    assert quest.status == "in_progress"
    print("  [PASS] Quest status transitions")

    # Test objective completion
    obj_id = quest.objectives[0]["id"]
    quest = hub.quests.complete_objective(quest.id, user1.id, obj_id)
    assert quest.objectives[0]["is_completed"] is True
    assert quest.progress > 0
    print("  [PASS] Objective completion")

    # Test quest collaboration
    quest = hub.quests.add_collaborator(quest.id, user1.id, user2.id)
    assert user2.id in quest.collaborator_ids
    print("  [PASS] Quest collaboration")

    # Test quest search
    results = hub.quests.search_quests("dragon")
    assert len(results) == 1
    print("  [PASS] Quest search")

    # Test skill plan creation
    plan = hub.skill_plans.create_plan(
        owner_id=user1.id,
        name="Knight Build v2",
        character_name="Sir Galahad",
        character_class="Paladin",
        target_level=80,
    )
    assert plan.name == "Knight Build v2"
    print("  [PASS] Skill plan creation")

    # Test adding skills
    plan = hub.skill_plans.add_skill(
        plan.id, user1.id, "Swordsmanship", "combat",
        description="Mastery of blade techniques", current_level=15
    )
    plan = hub.skill_plans.add_skill(
        plan.id, user1.id, "Holy Magic", "magic",
        description="Divine healing and protection spells", current_level=10
    )
    assert len(plan.skills) == 2
    print("  [PASS] Skill management")

    # Test skill update
    skill_id = plan.skills[0]["id"]
    plan = hub.skill_plans.update_skill(plan.id, user1.id, skill_id, current_level=20)
    assert plan.skills[0]["current_level"] == 20
    print("  [PASS] Skill update")

    # Test collaboration session
    collab = hub.collaboration.create_or_join_session("quest", quest.id, user1.id)
    assert collab.resource_id == quest.id
    assert user1.id in collab.participants
    print("  [PASS] Collaboration session creation")

    # Test joining session
    collab = hub.collaboration.create_or_join_session("quest", quest.id, user2.id)
    assert user2.id in collab.participants
    print("  [PASS] Collaboration session join")

    # Test messaging
    msg = hub.collaboration.send_message(collab.id, user1.id, "Ready to fight the dragon!")
    assert msg.content == "Ready to fight the dragon!"
    msg2 = hub.collaboration.send_message(collab.id, user2.id, "Let me buff the party first")
    messages = hub.collaboration.get_messages(collab.id, user1.id)
    assert len(messages) == 2
    print("  [PASS] Real-time messaging")

    # Test dashboard
    dashboard = hub.get_dashboard(user1.id)
    assert dashboard["stats"]["total_quests"] == 1
    assert dashboard["stats"]["active_quests"] == 1
    assert dashboard["stats"]["total_skill_plans"] == 1
    print("  [PASS] Dashboard")

    # Test export
    json_export = hub.export_data(user1.id, "json")
    export_data = json.loads(json_export)
    assert len(export_data["quests"]) == 1
    assert len(export_data["skill_plans"]) == 1
    print("  [PASS] JSON export")

    csv_export = hub.export_data(user1.id, "csv")
    assert "Defeat the Dragon" in csv_export
    print("  [PASS] CSV export")

    # Test quest completion
    quest = hub.quests.update_status(quest.id, user1.id, "completed")
    assert quest.status == "completed"
    assert quest.completed_at is not None
    assert quest.progress == 100.0
    print("  [PASS] Quest completion")

    # Test thread safety
    import concurrent.futures
    errors = []

    def create_quest_thread(i):
        try:
            hub.quests.create_quest(
                owner_id=user1.id,
                title=f"Thread Quest {i}",
                description=f"Created by thread {i}",
            )
        except Exception as e:
            errors.append(str(e))

    with concurrent.futures.ThreadPoolExecutor(max_workers=8) as executor:
        futures = [executor.submit(create_quest_thread, i) for i in range(50)]
        concurrent.futures.wait(futures)

    assert len(errors) == 0
    quests = hub.quests.list_quests(owner_id=user1.id, limit=1000)
    assert len(quests) == 51  # 1 original + 50 threaded
    print("  [PASS] Thread safety (50 concurrent quest creates)")

    # Test validation
    try:
