    assert user2.id not in session.participants
    print("  [PASS] Leave collaboration")

    # Test quest deletion
    quest2 = hub.quests.create_quest(user1.id, "Temp Quest", "To delete")
    hub.quests.delete_quest(quest2.id, user1.id)
    try:
        hub.quests.get_quest(quest2.id)
