    except NotFoundError:
        pass
    print("  [PASS] Quest deletion")

    # Test skill plan deletion
    plan2 = hub.skill_plans.create_plan(user1.id, "Temp Plan")
    hub.skill_plans.delete_plan(plan2.id, user1.id)
    try:
        hub.skill_plans.get_plan(plan2.id)
        assert False, "Should have raised NotFoundError"
    except NotFoundError:
        pass
    print("  [PASS] Skill plan deletion")

    # Test password change
    hub.auth.change_password(user1.id, "sword123", "newsword789")
    _, new_token = hub.auth.login("hero_knight", "newsword789")
    assert new_token
    print("  [PASS] Password change")

    # Test logout
    hub.auth.logout(token)
    try:
        hub.auth.authenticate(token)
        assert False, "Should have raised AuthenticationError"
    except AuthenticationError:
        pass
    print("  [PASS] Logout / session invalidation")

    print("\n=== All smoke tests PASSED ===")
    return True


